#define ETA 0.3f
#define MOMENTUM 0.3f
#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16

float squash(float x)
{
    return (1.0f / (1.0f + exp(-x)));
}

kernel void bpnn_layerforward_ocl(global float* input, global float* output, 
                                   global float* weights, global float* partial_sum,
                                   local float* local_mem, local float* local_weights,
                                   int n1, int n2)
{
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= n2) {
        float sum = 0.0f;

        for (int i = 0; i <= n1; i++) {
            sum += weights[i * (n2 + 1) + j] * input[i];
        }

        output[j] = squash(sum);

        if (k < BLOCK_SIZE && j <= n2) {
            partial_sum[(j - 1) * BLOCK_SIZE + k] = weights[k * (n2 + 1) + j] * input[k];
        }
    }
}

kernel void bpnn_adjust_weights_ocl(global float* delta, int ndelta,
                                     global float* ly, int nly,
                                     global float* w, global float* oldw)
{
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k <= nly) {
        float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k * ndelta + j]);
        w[k * ndelta + j] += new_dw;
        oldw[k * ndelta + j] = new_dw;
    }
}
